1190 OffsetSpan ObjectSizeOffsetVisitor::combineOffsetRange(OffsetSpan LHS,
1191                                                        OffsetSpan RHS) {
1192   if (!LHS.bothKnown() || !RHS.bothKnown())
1193     return ObjectSizeOffsetVisitor::unknown();
1194 
1195   switch (Options.EvalMode) {
1196   case ObjectSizeOpts::Mode::Min:
1197     return {LHS.Before.slt(RHS.Before) ? LHS.Before : RHS.Before,
1198             LHS.After.slt(RHS.After) ? LHS.After : RHS.After};
1199   case ObjectSizeOpts::Mode::Max: {
1200     return {LHS.Before.sgt(RHS.Before) ? LHS.Before : RHS.Before,
1201             LHS.After.sgt(RHS.After) ? LHS.After : RHS.After};
1202   }
1203   case ObjectSizeOpts::Mode::ExactSizeFromOffset:
1204     return {LHS.Before.eq(RHS.Before) ? LHS.Before : APInt(),
1205             LHS.After.eq(RHS.After) ? LHS.After : APInt()};
1206   case ObjectSizeOpts::Mode::ExactUnderlyingSizeAndOffset:
1207     return (LHS == RHS) ? LHS : ObjectSizeOffsetVisitor::unknown();
1208   }
1209   llvm_unreachable("missing an eval mode");
1210 }
