1259   SizeOffsetValue Result = compute_(V);
1260 
1261   if (!Result.bothKnown()) {
1262     // Erase everything that was computed in this iteration from the cache, so
1263     // that no dangling references are left behind. We could be a bit smarter if
1264     // we kept a dependency graph. It's probably not worth the complexity.
1265     for (const Value *SeenVal : SeenVals) {
