1061 OffsetSpan ObjectSizeOffsetVisitor::findLoadOffsetRange(
1062     LoadInst &Load, BasicBlock &BB, BasicBlock::iterator From,
1063     SmallDenseMap<BasicBlock *, OffsetSpan, 8> &VisitedBlocks,
1064     unsigned &ScannedInstCount) {
1065   constexpr unsigned MaxInstsToScan = 128;
1066 
1067   auto Where = VisitedBlocks.find(&BB);
1068   if (Where != VisitedBlocks.end())
1069     return Where->second;
1070 
1071   auto Unknown = [&BB, &VisitedBlocks]() {
1072     return VisitedBlocks[&BB] = ObjectSizeOffsetVisitor::unknown();
1073   };
1074   auto Known = [&BB, &VisitedBlocks](OffsetSpan SO) {
1075     return VisitedBlocks[&BB] = SO;
1076   };
1077 
1078   do {
1079     Instruction &I = *From;
1080 
1081     if (I.isDebugOrPseudoInst())
1082       continue;
1083 
1084     if (++ScannedInstCount > MaxInstsToScan)
1085       return Unknown();
1086 
1087     if (!I.mayWriteToMemory())
1088       continue;
1089 
1090     if (auto *SI = dyn_cast<StoreInst>(&I)) {
1091       AliasResult AR =
1092           Options.AA->alias(SI->getPointerOperand(), Load.getPointerOperand());
1093       switch ((AliasResult::Kind)AR) {
1094       case AliasResult::NoAlias:
1095         continue;
1096       case AliasResult::MustAlias:
1097         if (SI->getValueOperand()->getType()->isPointerTy())
1098           return Known(computeImpl(SI->getValueOperand()));
1099         else
1100           return Unknown(); // No handling of non-pointer values by `compute`.
1101       default:
1102         return Unknown();
1103       }
1104     }
1105 
1106     if (auto *CB = dyn_cast<CallBase>(&I)) {
1107       Function *Callee = CB->getCalledFunction();
1108       // Bail out on indirect call.
1109       if (!Callee)
1110         return Unknown();
1111 
1112       LibFunc TLIFn;
1113       if (!TLI || !TLI->getLibFunc(*CB->getCalledFunction(), TLIFn) ||
1114           !TLI->has(TLIFn))
1115         return Unknown();
1116 
1117       // TODO: There's probably more interesting case to support here.
1118       if (TLIFn != LibFunc_posix_memalign)
1119         return Unknown();
1120 
1121       AliasResult AR =
1122           Options.AA->alias(CB->getOperand(0), Load.getPointerOperand());
1123       switch ((AliasResult::Kind)AR) {
1124       case AliasResult::NoAlias:
1125         continue;
1126       case AliasResult::MustAlias:
1127         break;
1128       default:
1129         return Unknown();
1130       }
1131 
1132       // Is the error status of posix_memalign correctly checked? If not it
1133       // would be incorrect to assume it succeeds and load doesn't see the
1134       // previous value.
1135       std::optional<bool> Checked = isImpliedByDomCondition(
1136           ICmpInst::ICMP_EQ, CB, ConstantInt::get(CB->getType(), 0), &Load, DL);
1137       if (!Checked || !*Checked)
1138         return Unknown();
1139 
1140       Value *Size = CB->getOperand(2);
1141       auto *C = dyn_cast<ConstantInt>(Size);
1142       if (!C)
1143         return Unknown();
1144 
1145       APInt CSize = C->getValue();
1146       if (CSize.isNegative())
1147         return Unknown();
1148 
1149       return Known({APInt(CSize.getBitWidth(), 0), CSize});
1150     }
1151 
1152     return Unknown();
1153   } while (From-- != BB.begin());
1154 
1155   SmallVector<OffsetSpan> PredecessorSizeOffsets;
1156   for (auto *PredBB : predecessors(&BB)) {
1157     PredecessorSizeOffsets.push_back(findLoadOffsetRange(
1158         Load, *PredBB, BasicBlock::iterator(PredBB->getTerminator()),
1159         VisitedBlocks, ScannedInstCount));
1160     if (!PredecessorSizeOffsets.back().bothKnown())
1161       return Unknown();
1162   }
1163 
1164   if (PredecessorSizeOffsets.empty())
1165     return Unknown();
1166 
1167   return Known(std::accumulate(
1168       PredecessorSizeOffsets.begin() + 1, PredecessorSizeOffsets.end(),
1169       PredecessorSizeOffsets.front(), [this](OffsetSpan LHS, OffsetSpan RHS) {
1170         return combineOffsetRange(LHS, RHS);
1171       }));
