 889   if (ORT.knownBefore()) {
 890     bool Overflow;
 891     ORT.Before = ORT.Before.sadd_ov(Offset, Overflow);
 892     if (Overflow)
 893       ORT.Before = APInt();
 894   }
 895   if (ORT.knownAfter()) {
 896     bool Overflow;
 897     ORT.After = ORT.After.ssub_ov(Offset, Overflow);
 898     if (Overflow)
 899       ORT.After = APInt();
