 982 OffsetSpan ObjectSizeOffsetVisitor::visitArgument(Argument &A) {
 983   Type *MemoryTy = A.getPointeeInMemoryValueType();
 984   // No interprocedural analysis is done at the moment.
 985   if (!MemoryTy|| !MemoryTy->isSized()) {
